import React, { useState } from "react";
import logo from "./images/logo.jpeg";
import Navbar from "react-bootstrap/Navbar";
import Container from "react-bootstrap/Container";
import { Card } from "react-bootstrap";
import Nav from "react-bootstrap/Nav";
import Form from "react-bootstrap/Form";
import Button from "react-bootstrap/Button";
import Row from "react-bootstrap/Row";
import Col from "react-bootstrap/Col";
import "./upload.css";
import { useNavigate, Link } from "react-router-dom";

function UploadPage() {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [data, setData] = useState({ search: "" });
  const [videos, setVideos] = useState([]);

  const handleInputChange = (event) => {
    const { name, value } = event.target;
    setData((prevFormData) => ({
      ...prevFormData,
      [name]: value,
    }));
  };

  const handleSearch = async (e) => {
    e.preventDefault();

    if (!data.search) {
      alert("Please enter a search term");
      return;
    }

    setLoading(true);

    try {
      const token = sessionStorage.getItem("token"); // Retrieve the token
      if (!token) {
        alert("Please log in to perform this action");
        navigate("/");
        return;
      }

      const response = await fetch("http://localhost:5000/api/search", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({ search: data.search }), // Send the search data as JSON
      });

      if (!response.ok) {
        const errorMessage = await response.text();
        alert(`Failed to fetch: ${errorMessage}`);
        return;
      }

      const responseData = await response.json();
      setVideos(responseData.videos);
      console.log(responseData.message);
    } catch (error) {
      console.error("Error fetching videos:", error);
      alert("An error occurred while searching for the video. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  // Function to format video duration (e.g., PT10M15S to 10m 15s)
  const formatDuration = (duration) => {
    const match = duration.match(/PT(\d+H)?(\d+M)?(\d+S)?/);
    const hours = match[1] ? parseInt(match[1]) : 0;
    const minutes = match[2] ? parseInt(match[2]) : 0;
    const seconds = match[3] ? parseInt(match[3]) : 0;

    return `${hours > 0 ? `${hours}h ` : ""}${minutes > 0 ? `${minutes}m ` : ""}${seconds}s`;
  };

  return (
    <div>
      <Navbar className="bg-body-tertiary justify-content-between">
        <Container>
          <Navbar.Brand href="#home">
            <img
              src={logo}
              width="30"
              height="30"
              className="d-inline-block align-top"
              alt="React Bootstrap logo"
            />
          </Navbar.Brand>
          <Navbar.Toggle aria-controls="basic-navbar-nav" />
          <Navbar.Collapse id="basic-navbar-nav">
            <Nav className="me-auto">
              <Nav.Link as={Link} to="/home">
                Home
              </Nav.Link>
              <Nav.Link as={Link} to="/">
                Login
              </Nav.Link>
              <Nav.Link as={Link} to="/register">
                Registration
              </Nav.Link>
            </Nav>
            <Form onSubmit={handleSearch}>
              <Row>
                <Col xs="auto">
                  <Form.Control
                    type="text"
                    placeholder="Search"
                    className="mr-sm-2 search"
                    onChange={handleInputChange}
                    name="search"
                    value={data.search}
                  />
                </Col>
                <Col xs="auto">
                  <Button type="submit" disabled={loading}>
                    {loading ? "Searching..." : "Search"}
                  </Button>
                </Col>
              </Row>
            </Form>
          </Navbar.Collapse>
        </Container>
      </Navbar>

      <Container className="mt-4">
        <h4 className="text-center">Choose a Chapter</h4>
        {videos.length > 0 ? (
          <Row className="justify-content-center">
            {videos.map((video) => (
              <Col key={video.id} xs={12} sm={6} md={4} lg={3} className="mb-4">
                <Card className="h-100 text-center">
                  <a
                    href={`https://www.youtube.com/watch?v=${video.id}`}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="text-decoration-none"
                  >
                    <Card.Img
                      variant="top"
                      src={video.thumbnail.replace('default', 'hqdefault')}
                      alt={video.title}
                      style={{ height: "200px", objectFit: "cover" }}
                    />
                    <Card.Body>
                      <Card.Title className="text-truncate">{video.title}</Card.Title>
                      <Card.Text>
                        <small>
                          Duration: {formatDuration(video.duration)} 
                        </small>
                      </Card.Text>
                    </Card.Body>
                  </a>
                </Card>
              </Col>
            ))}
          </Row>
        ) : (
          <p className="text-center">No videos found.</p>
        )}
      </Container>
    </div>
  );
}

export default UploadPage;
